import java.util.Scanner;
public class Main {
    public static int nCr(int n, int r) {
        if (r > n - r) r = n - r;
        int ans = 1;
        for (int i = 1; i <= r; i++) {
            ans = ans * (n - i + 1) / i;
        }
        return ans;
    }
    public static int solve(int k, int[] n) {
        int m = 0;
        for (int i = 0; i < k; i++) {
            m += n[i];
        }
        int min_m = m;
        for (int mask = 0; mask < (1 << k); mask++) {
            int sum = 0;
            for (int i = 0; i < k; i++) {
                if ((mask & (1 << i)) != 0) {
                    sum += nCr(n[i], 2);
                }
            }
            if (sum % 2 == 0) {
                min_m = Math.min(min_m, Integer.bitCount(mask));
            }
        }
        return min_m == m ? -1 : min_m;
