import math

def nCr(n, r):
    if r > n - r: r = n - r
    ans = 1
    for i in range(1, r + 1):
        ans = ans * (n - i + 1) // i
    return ans

def solve(k, n):
    m = sum(n)
    min_m = m
    for mask in range(1 << k):
        sum = 0
        for i in range(k):
            if (mask & (1 << i)) != 0:
                sum += nCr(n[i], 2)
        if sum % 2 == 0:
            min_m = min(min_m, bin(mask).count('1'))
    return min_m if min_m != m else -1

t = int(input())
while t > 0:
    k = int(input())
    n = list(map(int, input().split()))
    print(solve(k, n))
    t -= 1

